async (page) => {
  var title = "图解 Blaze · 第 17 章 · GraphQL 集成 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 17 章 · GraphQL 集成</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">GraphQL 自动映射 · Relay 分页 · Entity View → GraphQL 类型 · N+1 消除</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">GraphQL 的核心理念是\"客户端按需选择字段\"，而 Entity View 的核心理念是\"只投影需要的列\"。两者天然同构，结合使用可以在整条数据通路上实现精准投影 — 从前端 GraphQL 查询，到 Entity View 映射，最终生成只包含必要列的 SQL。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">理解 GraphQL 字段选择与 Entity View 投影的同构关系</li><li style=\"margin-bottom:4px;font-size:13px;\">通过 Entity View 接口自动生成 GraphQL 类型</li><li style=\"margin-bottom:4px;font-size:13px;\">基于 Keyset 分页实现 Relay 规范的 Connection 分页</li><li style=\"margin-bottom:4px;font-size:13px;\">利用 GraphQL 字段选择驱动 Entity View 按需加载，消除 N+1</li><li style=\"margin-bottom:4px;font-size:13px;\">在 Spring for GraphQL 和 SmallRye GraphQL (Quarkus) 中实战集成</li><li style=\"margin-bottom:4px;font-size:13px;\">规避循环引用、深层嵌套、Mutation 等常见陷阱</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 4 章 · Entity View 基础</span>、<span style=\"color:#1e6fff;\">第 10 章 · Keyset 分页</span>。</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.1 GraphQL 与 Entity View 的天然契合</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">GraphQL 和 Entity View 在设计哲学上高度一致：前者让客户端声明\"我要哪些字段\"，后者让服务端声明\"只查询哪些列\"。将两者串联起来，可以实现端到端的精准投影。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">端到端投影 — 从 GraphQL 查询到最小 SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">id</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">GraphQL 查询<br/>{ order { id name items { sku } } }</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">字段解析器<br/>提取 selected fields</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Entity View<br/>按需激活字段映射</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">CriteriaBuilder<br/>仅 JOIN 必要表</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">最小 SQL<br/>SELECT o.id, o.name,<br/>i.sku FROM ...</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">同构关系：GraphQL 类型 ≈ Entity View 接口</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">GraphQL type 定义的每个 field 与 Entity View 接口的每个 getter 方法一一对应。这种同构关系使得自动映射成为可能。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">GraphQL Type 与 Entity View 接口的同构映射</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">GQL_SCHEMA</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">type Order {<br/>  id: ID!<br/>  customerName: String!<br/>  totalAmount: BigDecimal<br/>  items: [OrderItem!]!<br/>}</p></section></section><p style=\"text-align:center;font-size:11px;color:#888;margin:2px 0 0;line-height:1.3;\">字段 1:1 对应</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EV_JAVA</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@EntityView(Order.class)<br/>interface OrderView {<br/>  Long getId();<br/>  String getCustomerName();<br/>  BigDecimal getTotalAmount();<br/>  List<OrderItemView> getItems();<br/>}</p></section></section><p style=\"text-align:center;font-size:11px;color:#888;margin:2px 0 0;line-height:1.3;\">属性映射</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JPA</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@Entity Order {<br/>  Long id;<br/>  String customerName;<br/>  BigDecimal totalAmount;<br/>  List<OrderItem> items;<br/>}</p></section></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">为什么 Entity View 天然解决 GraphQL N+1</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">传统 GraphQL resolver 采用\"逐字段解析\"模式 — 每个嵌套类型触发一次数据库查询。而 Entity View 在查询构建阶段就确定了所有需要的关联和列，生成单条优化 SQL。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">传统 DataFetcher (N+1) vs Entity View (单次查询)</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Client</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Resolver</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 ❌ 传统 DataFetcher 方式</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 ✅ Entity View 方式</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 传统方式: 1+N 条 SQL ❌[BR]Entity View: 1 条 SQL ✅</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 核心洞见：</strong>GraphQL 的字段选择机制与 Entity View 的投影机制在语义上完全等价。将两者结合，意味着客户端的 GraphQL 查询直接驱动数据库只 SELECT 和 JOIN 必要的列与表 — 无需中间 DTO 转换层。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.2 自动类型映射</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的 GraphQL 集成模块能够将 Entity View 接口自动转换为 GraphQL schema 类型。每个 getter 方法映射为一个 GraphQL field，Java 类型映射为 GraphQL 标量或对象类型。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Entity View → GraphQL 类型自动映射规则</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n\nEntity View 字段类型GraphQL Schema 类型\n\n\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Long / Integer</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ID! / Int!</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">String</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">String!</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">BigDecimal</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">BigDecimal</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Boolean</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Boolean!</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LocalDate / LocalDateTime</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Date / DateTime</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SubView</code> (嵌套视图)→嵌套 Object Type\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">List<SubView></code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">[ObjectType!]!</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Set<SubView></code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">[ObjectType!]!</code>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">enum</code>→<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Enum Type</code>\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Entity View 定义与生成的 GraphQL Schema</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Entity View 接口定义</span><br/>@EntityView(Order.class)<br/>public interface OrderView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getCustomerName();<br/>    BigDecimal getTotalAmount();<br/>    OrderStatus getStatus();<br/>    LocalDateTime getCreatedAt();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// Subview 嵌套 → GraphQL 嵌套类型</span><br/>    List&lt;OrderItemView&gt; getItems();<br/>    CustomerView getCustomer();<br/>}<br/><br/>@EntityView(OrderItem.class)<br/>public interface OrderItemView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getSku();<br/>    String getProductName();<br/>    Integer getQuantity();<br/>    BigDecimal getUnitPrice();<br/>}<br/><br/>@EntityView(Customer.class)<br/>public interface CustomerView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getName();<br/>    String getEmail();<br/>}</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">上述接口自动生成以下 GraphQL schema：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># 自动生成的 GraphQL Schema</span><br/>type Order {<br/>    id: ID!<br/>    customerName: String!<br/>    totalAmount: BigDecimal<br/>    status: OrderStatus!<br/>    createdAt: DateTime<br/>    items: [OrderItem!]!<br/>    customer: Customer!<br/>}<br/><br/>type OrderItem {<br/>    id: ID!<br/>    sku: String!<br/>    productName: String!<br/>    quantity: Int!<br/>    unitPrice: BigDecimal<br/>}<br/><br/>type Customer {<br/>    id: ID!<br/>    name: String!<br/>    email: String!<br/>}<br/><br/>enum OrderStatus {<br/>    PENDING<br/>    CONFIRMED<br/>    SHIPPED<br/>    DELIVERED<br/>    CANCELLED<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Subview 嵌套 → GraphQL 嵌套类型</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Subview 嵌套递归转换为 GraphQL 类型图</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EV_LAYER</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderView</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderItemView</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CustomerView</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ProductView</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">GQL_LAYER</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">type Order</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">type OrderItem</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">type Customer</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">type Product</p></section></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 零样板代码：</strong>Entity View 的 Subview 嵌套关系直接转化为 GraphQL 的类型嵌套。无需手动编写 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.graphqls</code> schema 文件 — Entity View 接口就是 schema 的唯一来源（Schema-from-Code）。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.3 Relay 规范分页</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Relay 规范要求分页接口遵循 Connection / Edge / Node 模式，使用 cursor 定位而非 offset 偏移。Blaze-Persistence 的 Keyset 分页与 Relay cursor 天然对应 — keyset 元组编码为 cursor 字符串。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Relay 分页数据模型</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Connection<br/>(OrderConnection)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PageInfo<br/>hasNextPage<br/>hasPreviousPage<br/>startCursor<br/>endCursor</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">edges: [Edge]</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Edge #1<br/>cursor: abc123<br/>node: Order</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Edge #2<br/>cursor: def456<br/>node: Order</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Edge #3<br/>cursor: ghi789<br/>node: Order</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Relay Cursor ↔ Keyset 分页的对应关系</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Relay 查询完整流程 — 从 GraphQL 到 SQL</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Client</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Resolver</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 利用 (created_at, id) 索引[BR]无论翻到第几页，性能恒定 ✅</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Connection/Edge/Node 类型定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># Relay 规范的 Connection 类型</span><br/>type OrderConnection {<br/>    edges: [OrderEdge!]!<br/>    pageInfo: PageInfo!<br/>    totalCount: Int<br/>}<br/><br/>type OrderEdge {<br/>    cursor: String!<br/>    node: Order!<br/>}<br/><br/>type PageInfo {<br/>    hasNextPage: Boolean!<br/>    hasPreviousPage: Boolean!<br/>    startCursor: String<br/>    endCursor: String<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码实现：Entity View + Relay 分页</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Controller<br/>public class OrderGraphQLController {<br/><br/>    @Autowired<br/>    private CriteriaBuilderFactory cbf;<br/>    @Autowired<br/>    private EntityViewManager evm;<br/>    @Autowired<br/>    private EntityManager em;<br/><br/>    @QueryMapping<br/>    public OrderConnection orders(<br/>            @Argument Integer first,<br/>            @Argument String after) {<br/><br/>        EntityViewSetting&lt;OrderView, PaginatedCriteriaBuilder&lt;OrderView&gt;&gt;<br/>            setting = EntityViewSetting.create(OrderView.class, 0, first);<br/><br/>        <span style=\"color:#6c7086;font-style:italic;\">// 解码 Relay cursor → keyset</span><br/>        if (after != null) {<br/>            KeysetPage keyset = decodeCursor(after);<br/>            setting = EntityViewSetting.create(OrderView.class, keyset, first);<br/>        }<br/><br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>            .orderByAsc(\"createdAt\")<br/>            .orderByAsc(\"id\");<br/><br/>        PagedList&lt;OrderView&gt; page = evm.applySetting(setting, cb)<br/>            .getResultList();<br/><br/>        return toRelayConnection(page);<br/>    }<br/><br/>    private OrderConnection toRelayConnection(PagedList&lt;OrderView&gt; page) {<br/>        List&lt;OrderEdge&gt; edges = page.stream()<br/>            .map(node -&gt; new OrderEdge(<br/>                encodeCursor(page.getKeysetPage(), node),<br/>                node))<br/>            .collect(Collectors.toList());<br/><br/>        PageInfo pageInfo = new PageInfo(<br/>            page.getTotalSize() &gt; page.getMaxResults() + page.getFirstResult(),<br/>            page.getFirstResult() &gt; 0,<br/>            edges.isEmpty() ? null : edges.get(0).getCursor(),<br/>            edges.isEmpty() ? null : edges.get(edges.size()-1).getCursor());<br/><br/>        return new OrderConnection(edges, pageInfo, (int) page.getTotalSize());<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 Relay = Keyset：</strong>Relay cursor 本质上就是序列化的 keyset 元组。Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetAwarePage</code> 直接提供 keyset 信息，只需 Base64 编码/解码即可生成符合 Relay 规范的 cursor。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.4 查询优化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">GraphQL 的真正威力在于客户端按需选择字段。当这个选择信息传递到 Entity View 层时，Blaze-Persistence 可以在 SQL 层面实现极致的精准投影 — 客户端不要的字段，数据库根本不会查询。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">字段选择驱动的 SQL 精简流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DataFetchingEnvironment<br/>.getSelectionSet()</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">getSelectionSet</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting<br/>.fetch('id', 'name')</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">fetch</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">o</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">id</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DataFetchingEnvironment<br/>.getSelectionSet()</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting<br/>.fetch('id', 'name', 'items.sku', 'items.qty')</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">GraphQL 查询<br/>{ order { id name } }</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder<br/>仅 SELECT id, name<br/>无 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT o.id, o.customer_name<br/>FROM orders o<br/>WHERE o.id = ?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">GraphQL 查询<br/>{ order { id name items { sku qty } } }</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder<br/>SELECT + JOIN items</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT o.id, o.customer_name,<br/>i.sku, i.quantity<br/>FROM orders o<br/>LEFT JOIN items i ON ...</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Entity View 字段按需加载</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@QueryMapping<br/>public OrderView order(@Argument Long id,<br/>                       DataFetchingEnvironment env) {<br/><br/>    EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt;<br/>        setting = EntityViewSetting.create(OrderView.class);<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 从 GraphQL 选择集提取需要的字段</span><br/>    Set&lt;String&gt; selectedFields = env.getSelectionSet()<br/>        .getImmediateFields().stream()<br/>        .map(SelectedField::getName)<br/>        .collect(Collectors.toSet());<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 仅 fetch 被选中的字段</span><br/>    setting.fetch(selectedFields.toArray(new String[0]));<br/><br/>    CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>        .where(\"id\").eq(id);<br/><br/>    return evm.applySetting(setting, cb).getSingleResult();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">N+1 消除对比</h3></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">批量加载嵌套关联</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当 Entity View 包含多个集合关联时，使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MULTISET</code> 策略可以在单条 SQL 中完成所有嵌套数据的加载：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderGraphQLView {<br/>    @IdMapping<br/>    Long getId();<br/>    String getCustomerName();<br/><br/>    @Mapping(fetch = FetchStrategy.MULTISET)<br/>    List&lt;OrderItemView&gt; getItems();<br/><br/>    @Mapping(fetch = FetchStrategy.MULTISET)<br/>    List&lt;ShipmentView&gt; getShipments();<br/><br/>    @Mapping(fetch = FetchStrategy.JOIN)<br/>    CustomerView getCustomer();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">MULTISET 策略下的 GraphQL 嵌套查询执行</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Client</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Resolver</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 1 条 SQL 加载订单+子项+物流+客户 ✅</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 字段选择粒度：</strong>当 GraphQL 客户端未请求 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">items</code> 字段时，Entity View 不应触发 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">items</code> 表的 JOIN。确保 Resolver 层根据 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DataFetchingEnvironment</code> 动态构建 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSetting</code>，而非始终加载所有字段。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.5 Spring for GraphQL 集成</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Spring for GraphQL（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">spring-graphql</code>）是 Spring 官方的 GraphQL 框架，与 Spring Boot 深度集成。Blaze-Persistence Entity View 可以作为 GraphQL resolver 的返回类型，无缝对接。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Spring for GraphQL + Entity View 架构总览</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n客户端\nHTTP POST /graphql<br/>WebSocket /graphql\n\n→\n\nSpring for GraphQL 层\nGraphQL Controller<br/>DataFetcher<br/>BatchLoader\n\n→\n\n业务层\nOrderService<br/>ProductService\n\n→\n\nBlaze-Persistence 层\nEntityViewManager<br/>EntityViewSetting<br/>CriteriaBuilderFactory\n\n→\n\n数据层\nEntityManager<br/>数据库\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整集成示例</h3></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">1. 依赖配置</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- pom.xml --&gt;<br/>&lt;dependency&gt;<br/>    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>    &lt;artifactId&gt;spring-boot-starter-graphql&lt;/artifactId&gt;<br/>&lt;/dependency&gt;<br/>&lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-integration-graphql&lt;/artifactId&gt;<br/>    &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>&lt;/dependency&gt;<br/>&lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-integration-entity-view-spring&lt;/artifactId&gt;<br/>    &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>&lt;/dependency&gt;</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">2. GraphQL Controller</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Controller<br/>public class OrderGraphQLController {<br/><br/>    @Autowired private OrderService orderService;<br/><br/>    @QueryMapping<br/>    public List&lt;OrderView&gt; orders(<br/>            DataFetchingEnvironment env) {<br/>        Set&lt;String&gt; fields = extractFields(env);<br/>        return orderService.findAll(fields);<br/>    }<br/><br/>    @QueryMapping<br/>    public OrderDetailView order(<br/>            @Argument Long id,<br/>            DataFetchingEnvironment env) {<br/>        return orderService.findById(id, extractFields(env));<br/>    }<br/><br/>    @QueryMapping<br/>    public OrderConnection orderConnection(<br/>            @Argument Integer first,<br/>            @Argument String after,<br/>            DataFetchingEnvironment env) {<br/>        return orderService.findPaginated(first, after, extractFields(env));<br/>    }<br/><br/>    @MutationMapping<br/>    public OrderDetailView createOrder(<br/>            @Argument OrderCreateInput input) {<br/>        return orderService.create(input);<br/>    }<br/><br/>    private Set&lt;String&gt; extractFields(DataFetchingEnvironment env) {<br/>        return env.getSelectionSet().getImmediateFields()<br/>            .stream()<br/>            .map(SelectedField::getName)<br/>            .collect(Collectors.toSet());<br/>    }<br/>}</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">3. Service 层 — EntityViewSetting 动态构建</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Service<br/>@Transactional(readOnly = true)<br/>public class OrderService {<br/><br/>    @Autowired private CriteriaBuilderFactory cbf;<br/>    @Autowired private EntityViewManager evm;<br/>    @PersistenceContext private EntityManager em;<br/><br/>    public List&lt;OrderView&gt; findAll(Set&lt;String&gt; fields) {<br/>        EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt;<br/>            setting = EntityViewSetting.create(OrderView.class);<br/><br/>        if (fields != null &amp;&amp; !fields.isEmpty()) {<br/>            setting.fetch(fields.toArray(new String[0]));<br/>        }<br/><br/>        return evm.applySetting(setting,<br/>                   cbf.create(em, Order.class))<br/>                   .getResultList();<br/>    }<br/><br/>    public OrderConnection findPaginated(<br/>            Integer first, String after, Set&lt;String&gt; fields) {<br/><br/>        int pageSize = first != null ? first : 20;<br/><br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>            .orderByAsc(\"createdAt\")<br/>            .orderByAsc(\"id\");<br/><br/>        PaginatedCriteriaBuilder&lt;OrderView&gt; pcb;<br/>        if (after != null) {<br/>            KeysetPage keyset = CursorCodec.decode(after);<br/>            pcb = evm.applySetting(<br/>                EntityViewSetting.create(OrderView.class, keyset, pageSize),<br/>                cb);<br/>        } else {<br/>            pcb = evm.applySetting(<br/>                EntityViewSetting.create(OrderView.class, 0, pageSize),<br/>                cb);<br/>        }<br/><br/>        PagedList&lt;OrderView&gt; page = pcb.getResultList();<br/>        return RelayMapper.toConnection(page);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">DataFetcher 与 BatchLoader 模式</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">BatchLoader 消除 N+1 的工作流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Engine</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">BatchLoader</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 收集同一层级的所有 customer id</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 批量收集完毕，统一发送</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 无论多少个订单引用客户[BR]仅 1 条 SQL ✅</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Configuration<br/>public class GraphQLBatchConfig {<br/><br/>    @Bean<br/>    public BatchLoaderRegistry batchLoaderRegistry(<br/>            CriteriaBuilderFactory cbf,<br/>            EntityViewManager evm,<br/>            EntityManager em) {<br/><br/>        BatchLoaderRegistry registry = new BatchLoaderRegistry();<br/><br/>        registry.forTypePair(Long.class, CustomerView.class)<br/>            .registerMappedBatchLoader((ids, env) -&gt; {<br/>                CriteriaBuilder&lt;Customer&gt; cb = cbf.create(em, Customer.class)<br/>                    .where(\"id\").in(ids);<br/><br/>                List&lt;CustomerView&gt; results = evm.applySetting(<br/>                    EntityViewSetting.create(CustomerView.class), cb)<br/>                    .getResultList();<br/><br/>                return Mono.just(results.stream()<br/>                    .collect(Collectors.toMap(<br/>                        CustomerView::getId, v -&gt; v)));<br/>            });<br/><br/>        return registry;<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 双重优化：</strong>Entity View 提供列级精准投影（仅 SELECT 需要的列），BatchLoader 提供行级批量加载（合并 N 次查询为 1 次 IN 查询）。两者组合使 GraphQL 查询性能接近手写 SQL。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.6 SmallRye GraphQL (Quarkus) 集成</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在 Quarkus 生态中，SmallRye GraphQL 是官方 GraphQL 实现（基于 MicroProfile GraphQL 规范）。Blaze-Persistence 同样可以在 Quarkus + SmallRye GraphQL 中无缝使用。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Quarkus + SmallRye GraphQL + Entity View 架构</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\nSmallRye GraphQL\nGraphQL Resource<br/>@GraphQLApi<br/>自动生成 Schema\n\n→\n\nCDI 容器\nOrderService<br/>EntityViewManager<br/>CriteriaBuilderFactory\n\n→\n\nPersistence 层\nEntityManager<br/>Agroal 连接池<br/>PostgreSQL\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Quarkus GraphQL 端点实现</h3></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">1. 依赖配置</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- pom.xml --&gt;<br/>&lt;dependency&gt;<br/>    &lt;groupId&gt;io.quarkus&lt;/groupId&gt;<br/>    &lt;artifactId&gt;quarkus-smallrye-graphql&lt;/artifactId&gt;<br/>&lt;/dependency&gt;<br/>&lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-integration-quarkus&lt;/artifactId&gt;<br/>    &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>&lt;/dependency&gt;</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">2. GraphQL Resource</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@GraphQLApi<br/>@ApplicationScoped<br/>public class OrderGraphQLResource {<br/><br/>    @Inject CriteriaBuilderFactory cbf;<br/>    @Inject EntityViewManager evm;<br/>    @Inject EntityManager em;<br/><br/>    @Query(\"orders\")<br/>    @Description(\"查询所有订单，支持分页\")<br/>    public List&lt;OrderView&gt; getOrders(<br/>            @DefaultValue(\"20\") int pageSize,<br/>            @DefaultValue(\"0\") int offset) {<br/><br/>        EntityViewSetting&lt;OrderView, PaginatedCriteriaBuilder&lt;OrderView&gt;&gt;<br/>            setting = EntityViewSetting.create(<br/>                OrderView.class, offset, pageSize);<br/><br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>            .orderByAsc(\"id\");<br/><br/>        return evm.applySetting(setting, cb).getResultList();<br/>    }<br/><br/>    @Query(\"order\")<br/>    @Description(\"按 ID 查询单个订单详情\")<br/>    public OrderDetailView getOrder(@Name(\"id\") Long id) {<br/>        EntityViewSetting&lt;OrderDetailView, CriteriaBuilder&lt;OrderDetailView&gt;&gt;<br/>            setting = EntityViewSetting.create(OrderDetailView.class);<br/><br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>            .where(\"id\").eq(id);<br/><br/>        return evm.applySetting(setting, cb).getSingleResult();<br/>    }<br/><br/>    @Mutation(\"createOrder\")<br/>    @Description(\"创建新订单\")<br/>    @Transactional<br/>    public OrderDetailView createOrder(OrderCreateInput input) {<br/>        OrderCreateView view = evm.create(OrderCreateView.class);<br/>        view.setCustomerName(input.getCustomerName());<br/>        evm.save(em, view);<br/>        return getOrder(view.getId());<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">SmallRye GraphQL 请求处理流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GraphQL Client</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SmallRye GraphQL</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">@GraphQLApi Resource</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">PostgreSQL</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 Quarkus Dev Mode 支持[BR]热重载 GraphQL schema</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 GraalVM 兼容：</strong>Blaze-Persistence 的 Quarkus 扩展在构建时完成 Entity View 元数据收集和代理类生成，使其与 GraalVM native-image 完全兼容。更多原生编译细节请参阅 <span style=\"color:#1e6fff;\">第 18 章</span>。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">17.7 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">GraphQL 与 Entity View 集成虽然强大，但在实际应用中仍需注意若干陷阱和限制。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">GraphQL + Entity View 六大陷阱全景图</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n陷阱 1 · 循环引用\n✅ 拆分视图 / @JsonIgnore<br/>打断循环链\n\n\n陷阱 2 · Mutation 复杂性\n✅ 分离读写视图<br/>Input 类型独立建模\n\n\n陷阱 3 · 深层嵌套性能\n✅ 设置最大深度<br/>查询复杂度限制\n\n\n陷阱 4 · Cursor 编解码\n✅ 统一 Base64 编解码<br/>加密防篡改\n\n\n陷阱 5 · Schema 演进\n✅ @Deprecated + 渐进废弃<br/>保持向后兼容\n\n\n陷阱 6 · Federation\n✅ 使用 @Key 字段<br/>按需启用 Entity Reference\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1：循环引用</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OrderView</code> 包含 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CustomerView</code>，而 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CustomerView</code> 又引用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">List<OrderView></code> 时，GraphQL schema 生成会陷入无限递归。</p></section>\n\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 打断循环：为不同方向创建精简视图</span><br/>@EntityView(Customer.class)<br/>public interface CustomerSummaryView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 不包含 getOrders() — 打断循环</span><br/>}<br/><br/>@EntityView(Order.class)<br/>public interface OrderView {<br/>    @IdMapping Long getId();<br/>    String getCustomerName();<br/>    CustomerSummaryView getCustomer(); <span style=\"color:#6c7086;font-style:italic;\">// 引用精简视图</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2：Mutation 复杂性</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">GraphQL Mutation 的输入类型（Input Types）与 Entity View 的 Updatable/Creatable 视图并非直接等价。需要独立定义 Input 类型，在 Resolver 层完成转换。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// GraphQL Input 类型 — 独立于 Entity View</span><br/>public class OrderCreateInput {<br/>    private String customerName;<br/>    private List&lt;OrderItemInput&gt; items;<br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters</span><br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// Resolver 层负责 Input → UpdatableView 转换</span><br/>@MutationMapping<br/>public OrderDetailView createOrder(@Argument OrderCreateInput input) {<br/>    OrderCreateView view = evm.create(OrderCreateView.class);<br/>    view.setCustomerName(input.getCustomerName());<br/><br/>    for (OrderItemInput item : input.getItems()) {<br/>        OrderItemCreateView itemView = evm.create(OrderItemCreateView.class);<br/>        itemView.setSku(item.getSku());<br/>        itemView.setQuantity(item.getQuantity());<br/>        view.getItems().add(itemView);<br/>    }<br/><br/>    evm.save(em, view);<br/>    return findById(view.getId());<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3：深层嵌套性能</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 查询深度失控：</strong>GraphQL 允许客户端无限嵌套查询（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">order.customer.orders.customer.orders...</code>），每增加一层嵌套都会产生额外的 JOIN。务必设置查询深度和复杂度限制。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># application.properties — Spring for GraphQL</span><br/>spring.graphql.graphiql.enabled=true<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># SmallRye GraphQL (Quarkus) — 查询复杂度限制</span><br/>quarkus.smallrye-graphql.events.enabled=true<br/>mp.graphql.maxComplexity=100<br/>mp.graphql.maxDepth=5</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 4：Cursor 编解码</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Relay cursor 应当是不透明的字符串。直接暴露 keyset 值（如数据库 ID）可能导致安全问题。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class CursorCodec {<br/>    private static final String HMAC_KEY = \"your-secret-key\";<br/><br/>    public static String encode(Serializable[] keyset) {<br/>        String json = new Gson().toJson(keyset);<br/>        String base64 = Base64.getUrlEncoder()<br/>            .encodeToString(json.getBytes(StandardCharsets.UTF_8));<br/>        String hmac = computeHmac(base64, HMAC_KEY);<br/>        return base64 + \".\" + hmac;<br/>    }<br/><br/>    public static Serializable[] decode(String cursor) {<br/>        String[] parts = cursor.split(\"\\\\.\");<br/>        if (parts.length != 2) throw new IllegalArgumentException(\"Invalid cursor\");<br/>        if (!computeHmac(parts[0], HMAC_KEY).equals(parts[1])) {<br/>            throw new SecurityException(\"Cursor tampered\");<br/>        }<br/>        String json = new String(<br/>            Base64.getUrlDecoder().decode(parts[0]),<br/>            StandardCharsets.UTF_8);<br/>        return new Gson().fromJson(json, Serializable[].class);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 5：Schema 演进</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Schema 演进策略 — 字段废弃流程</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">v1: Entity View<br/>getCustomerName()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">v2: 新增 getCustomer()<br/>@Deprecated getCustomerName()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">v3: 移除 getCustomerName()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">监控弃用字段使用率</p></section></td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderView {<br/>    @IdMapping Long getId();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// v1 字段 — 标记弃用，保留向后兼容</span><br/>    @Deprecated<br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// v2 新增：结构化的客户对象</span><br/>    CustomerSummaryView getCustomer();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 6：GraphQL Federation</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在微服务 GraphQL Federation 场景中，Entity View 需要通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Key</code> 字段配合实体引用（Entity Reference）机制工作。每个子图（Subgraph）只暴露自己拥有的 Entity View 字段。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Federation 中的 Entity View 分布</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">ORDER_SVC</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderView<br/>id, status, totalAmount<br/>customerId (引用)</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">CUSTOMER_SVC</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CustomerView<br/>@Key id<br/>name, email, tier</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">PRODUCT_SVC</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ProductView<br/>@Key sku<br/>name, price, stock</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">API Gateway<br/>(Apollo Router)</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">限制总结</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">限制项</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">影响</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">建议应对</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">循环引用</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Schema 生成失败 / 无限递归</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">拆分为 Summary / Detail 视图</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Mutation + UpdatableView</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Input 类型无法直接映射</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">独立定义 GraphQL Input，Resolver 层转换</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">深层嵌套</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">多层 JOIN 导致性能退化</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">设置 maxDepth / maxComplexity</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Cursor 安全性</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Keyset 值泄露</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Base64 + HMAC 签名</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Schema 演进</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">客户端兼容性</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">@Deprecated + 渐进废弃</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Federation</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">跨服务实体解析</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">@Key + __resolveReference</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Subscription</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Entity View 无原生支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">结合消息队列手动实现</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">File Upload</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">GraphQL 规范外扩展</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 REST 端点处理上传</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 📝 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\">GraphQL 与 Entity View 在\"按需投影\"理念上<strong style=\"color:#1a1a2e;font-weight:700;\">天然同构</strong> — GraphQL field ≈ Entity View getter ≈ SQL SELECT 列。</li><li style=\"margin-bottom:5px;font-size:14px;\">Entity View 接口可<strong style=\"color:#1a1a2e;font-weight:700;\">自动映射</strong>为 GraphQL 类型，Subview 嵌套直接对应 GraphQL 嵌套类型，实现 Schema-from-Code。</li><li style=\"margin-bottom:5px;font-size:14px;\">Relay 规范分页与 Keyset 分页<strong style=\"color:#1a1a2e;font-weight:700;\">一一对应</strong>：keyset 元组 Base64 编码后即为 cursor，PagedList 直接转换为 Connection/Edge/PageInfo。</li><li style=\"margin-bottom:5px;font-size:14px;\">GraphQL 字段选择通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DataFetchingEnvironment</code> 传递给 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSetting.fetch()</code>，实现<strong style=\"color:#1a1a2e;font-weight:700;\">端到端精准投影</strong>，从根本上消除 N+1 问题。</li><li style=\"margin-bottom:5px;font-size:14px;\">Spring for GraphQL 集成通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@QueryMapping</code> + Entity View 实现；BatchLoader 模式进一步优化<strong style=\"color:#1a1a2e;font-weight:700;\">关联数据批量加载</strong>。</li><li style=\"margin-bottom:5px;font-size:14px;\">Quarkus + SmallRye GraphQL 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@GraphQLApi</code> + CDI 注入 Blaze-Persistence 组件，完全兼容<strong style=\"color:#1a1a2e;font-weight:700;\">GraalVM 原生编译</strong>。</li><li style=\"margin-bottom:5px;font-size:14px;\">实际集成需注意<strong style=\"color:#1a1a2e;font-weight:700;\">循环引用、Mutation 建模、查询深度限制、Cursor 安全、Schema 演进</strong>等陷阱。</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 → <span style=\"color:#1e6fff;\">第 18 章 · Quarkus 与 GraalVM 原生编译</span>，深入探讨 Blaze-Persistence 在 Quarkus 生态中的构建时优化与 native-image 适配。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 17 章 · GraphQL 集成</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}